/** Differential and lifecycle coverage for same-snapshot parallel row pipelines. */
public class LmdbNativeParallelPipelinesTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String PARALLEL_FLAG = "rdf4j.lmdb.parallel.enabled";
	private static final String THRESHOLD_FLAG = "rdf4j.lmdb.parallel.minRootEstimate";
	private static final String THREADS_FLAG = "rdf4j.lmdb.parallel.threads";
	private static final String MAX_TASKS_FLAG = "rdf4j.lmdb.parallel.maxTasks";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		System.setProperty(THRESHOLD_FLAG, "0");
		System.setProperty(THREADS_FLAG, "4");
		System.setProperty(MAX_TASKS_FLAG, "5");
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI p3 = vf.createIRI(EX, "p3");
			connection.begin();
			for (int i = 0; i < 240; i++) {
				IRI subject = vf.createIRI(EX, "s" + i);
				IRI middle = vf.createIRI(EX, "m" + i);
				IRI tail = vf.createIRI(EX, "t" + i);
				connection.add(subject, p1, middle);
				connection.add(middle, p2, tail);
				for (int branch = 0; branch < 3; branch++) {
					connection.add(tail, p3, vf.createIRI(EX, "v" + i + "-" + branch));
				}
			}
			connection.commit();
		}
		resetCounters();
	}

	@AfterEach
	public void tearDown() {
		System.clearProperty(THRESHOLD_FLAG);
		System.clearProperty(THREADS_FLAG);
		System.clearProperty(MAX_TASKS_FLAG);
		System.clearProperty(PARALLEL_FLAG);
		System.clearProperty(NATIVE_FLAG);
		repository.shutDown();
	}

	@Test
	public void chainJoinProjectionMatchesSequentialAndGeneric() {
		String query = chain("");
		String physicalPlan;
		try (SailRepositoryConnection connection = repository.getConnection()) {
			physicalPlan = connection.prepareTupleQuery(query).explain(Explanation.Level.Optimized).toString();
			assertThat(physicalPlan)
					.contains("NativeRows")
					.contains("MultiJoin");
		}
		List<String> parallel = rows(query);
		assertThat(LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get())
				.as("parallel rejection: %s%n%s", LmdbNativeParallelPipelines.LAST_REJECTION.get(), physicalPlan)
				.isEqualTo(1L);
		assertThat(LmdbNativeParallelPipelines.OUTPUT_BATCHES.get()).isGreaterThan(1L);

		List<String> sequential = rowsWithProperty(PARALLEL_FLAG, "false", query);
		List<String> generic = rowsWithProperty(NATIVE_FLAG, "false", query);
		assertThat(parallel).hasSize(720).isEqualTo(sequential).isEqualTo(generic);
	}

	@Test
	public void immutableCompiledFilterRunsInsideWorkers() {
		String query = chain(" FILTER(BOUND(?value))");
		List<String> parallel = rows(query);
		assertThat(LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get()).isEqualTo(1L);
		assertThat(parallel).isEqualTo(rowsWithProperty(PARALLEL_FLAG, "false", query));
	}

	@Test
	public void earlyCloseCancelsWorkersAndLeavesStoreUsable() {
		long cancelled = LmdbNativeParallelPipelines.CANCELLED_RUNS.get();
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(chain("")).evaluate()) {
			assertThat(result.hasNext()).isTrue();
			result.next();
		}
		assertThat(LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get()).isEqualTo(1L);
		assertThat(LmdbNativeParallelPipelines.CANCELLED_RUNS.get()).isEqualTo(cancelled + 1L);
		try (SailRepositoryConnection connection = repository.getConnection()) {
			assertThat(connection.size()).isEqualTo(1_200L);
		}
	}

	@Test
	public void sliceAndActiveWriteStaySequential() {
		String query = chain("");
		rows(query + " LIMIT 5");
		assertThat(LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get()).isZero();

		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			connection.begin();
			IRI s = vf.createIRI(EX, "uncommitted-s");
			IRI m = vf.createIRI(EX, "uncommitted-m");
			IRI t = vf.createIRI(EX, "uncommitted-t");
			connection.add(s, vf.createIRI(EX, "p1"), m);
			connection.add(m, vf.createIRI(EX, "p2"), t);
			connection.add(t, vf.createIRI(EX, "p3"), vf.createIRI(EX, "uncommitted-value"));
			List<BindingSet> result = QueryResults.asList(connection.prepareTupleQuery(query).evaluate());
			assertThat(result).anySatisfy(row -> assertThat(row.getValue("subject")).isEqualTo(s));
			connection.rollback();
		}
		assertThat(LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get()).isZero();
	}

	@Test
	public void reservedWorkerGroupForcesSequentialFallback() {
		long before = LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get();
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult held = connection.prepareTupleQuery(highFanoutChain()).evaluate()) {
			assertThat(held.hasNext()).isTrue();
			assertThat(LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get()).isEqualTo(before + 1L);

			assertThat(rows(chain(""))).hasSize(720);
			assertThat(LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get())
					.as("the second complete worker group must fall back while the first owns the budget")
					.isEqualTo(before + 1L);
		}

		assertThat(rows(chain(""))).hasSize(720);
		assertThat(LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get()).isEqualTo(before + 2L);
	}

	@Test
	public void reservedWorkerGroupForcesAggregationFallback() {
		long before = LmdbNativeParallelAggregation.PARALLEL_RUNS.get();
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult held = connection.prepareTupleQuery(highFanoutChain()).evaluate()) {
			assertThat(held.hasNext()).isTrue();

			rows(aggregateChain());
			assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get())
					.as("aggregation must share the process task budget with row pipelines")
					.isEqualTo(before);
		}

		rows(aggregateChain());
		assertThat(LmdbNativeParallelAggregation.PARALLEL_RUNS.get()).isEqualTo(before + 1L);
	}

	private String chain(String filter) {
		return "SELECT ?subject ?value WHERE { ?subject <" + EX + "p1> ?middle . ?middle <" + EX
				+ "p2> ?tail . ?tail <" + EX + "p3> ?value ." + filter + " }";
	}

	private String highFanoutChain() {
		return "SELECT ?subject ?value ?value2 ?value3 WHERE { ?subject <" + EX
				+ "p1> ?middle . ?middle <" + EX + "p2> ?tail . ?tail <" + EX
				+ "p3> ?value . ?tail <" + EX + "p3> ?value2 . ?tail <" + EX + "p3> ?value3 . }";
	}

	private String aggregateChain() {
		return "SELECT (COUNT(?subject) AS ?count) WHERE { ?subject <" + EX
				+ "p1> ?middle . ?middle <" + EX + "p2> ?tail . ?tail <" + EX + "p3> ?value . }";
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ArrayList<String> rows = new ArrayList<>();
			for (BindingSet row : QueryResults.asList(connection.prepareTupleQuery(query).evaluate())) {
				rows.add(row.getValue("subject") + "|" + row.getValue("value"));
			}
			rows.sort(String::compareTo);
			return rows;
		}
	}

	private List<String> rowsWithProperty(String property, String value, String query) {
		String previous = System.getProperty(property);
		try {
			System.setProperty(property, value);
			return rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(property);
			} else {
				System.setProperty(property, previous);
			}
		}
	}

	private static void resetCounters() {
		LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.set(0L);
		LmdbNativeParallelPipelines.OUTPUT_BATCHES.set(0L);
		LmdbNativeParallelPipelines.CANCELLED_RUNS.set(0L);
		LmdbNativeParallelPipelines.WORKER_FAILURES.set(0L);
	}
}
